INSERT INTO posts (id, title, slug, excerpt, category, content, is_published, created_at, updated_at) VALUES ('bbcf777d-dd37-41e7-8a47-2a2a31cf363d', 'Building This Blog: From Idea to Deployment', 'building-this-blog', 'A transparent look at the decisions, tools, and trade-offs behind building a personal publishing platform from scratch — and what I learned along the way.', 'Engineering', '[{"type":"h1","text":"Building This Blog: From Idea to Deployment"},{"type":"paragraph","text":"A transparent look at the decisions, tools, and trade-offs behind building a personal publishing platform from scratch — and what I learned along the way."},{"type":"h2","text":"Why Build When You Can Buy?"},{"type":"paragraph","text":"Ghost, Substack, WordPress — the landscape of publishing tools is vast. But none of them felt quite right. I wanted full control over the reading experience, the ability to embed interactive components, and the satisfaction of owning every line of code. So I built my own."},{"type":"h2","text":"The Stack"},{"type":"paragraph","text":"React 19 handles the frontend with React Router for navigation. The backend is a lightweight Express server with a PostgreSQL database. Tailwind CSS v4 powers the styling, using CSS variables as design tokens rather than a config file. The result is a system that is fast to iterate on and easy to reason about."},{"type":"h2","text":"The CMS"},{"type":"paragraph","text":"The admin panel is a custom-built CMS with a block-based editor. Content is stored as a JSON array of typed blocks — headings, paragraphs, blockquotes, images. This makes it trivial to render content with precise typographic control, and easy to migrate or transform later."},{"type":"h2","text":"Deployment"},{"type":"paragraph","text":"The server runs on a single VPS. Vite handles the production build, and Express serves the static files. No containers, no orchestration — just a simple process that is easy to reason about and restart. Boring infrastructure is good infrastructure."},{"type":"paragraph","text":"The project is ongoing. Next up: full-text search, an RSS feed, and a more capable editor with image uploads. Building in public means shipping imperfect things — and that is the point."}]', true, '2025-11-10 14:30:00+05:30', '2025-11-10 14:30:00+05:30') ON CONFLICT DO NOTHING;
INSERT INTO posts (id, title, slug, excerpt, category, content, is_published, created_at, updated_at) VALUES ('7d2f9106-c489-4fa3-ae42-b2bdba5ee932', 'On Leaving Social Media (And What I Found in the Silence)', 'leaving-social-media', 'Eighteen months after deleting my last social media account, I have thoughts on boredom, attention, and what actually matters.', 'Journal', '[{"type":"h1","text":"On Leaving Social Media (And What I Found in the Silence)"},{"type":"paragraph","text":"Eighteen months after deleting my last social media account, I have thoughts on boredom, attention, and what actually matters."},{"type":"h2","text":"The Decision"},{"type":"paragraph","text":"It was not a grand gesture. I did not write a farewell post or explain myself. I simply stopped opening the apps, then deleted them, then deleted the accounts. The process took about ten minutes and caused no drama whatsoever, which itself said something."},{"type":"h2","text":"The First Month"},{"type":"paragraph","text":"The phantom phone checks were real. My thumb would reach for an app that was no longer there, then float awkwardly before I put the phone down. I had more time — but I did not know what to do with it at first. This is not a problem most people acknowledge: we are so accustomed to filling every gap that genuine unstructured time feels threatening."},{"type":"h2","text":"What Came Back"},{"type":"paragraph","text":"Reading long-form. Finishing books. Sitting with a problem for more than ninety seconds before reaching for distraction. A quality of attention that I had not noticed I had lost. I started writing again — not for an audience, just for the practice of thinking clearly."},{"type":"h2","text":"What I Miss"},{"type":"paragraph","text":"Genuinely: occasional good posts from people I respect, and the low-friction way social networks let you stay loosely connected to a large number of people. These are real costs. I have replaced them imperfectly with email, RSS, and the occasional phone call."},{"type":"paragraph","text":"The net is strongly positive. I recommend the experiment, even if only for a month."}]', true, '2025-12-01 15:30:00+05:30', '2025-12-01 15:30:00+05:30') ON CONFLICT DO NOTHING;
INSERT INTO posts (id, title, slug, excerpt, category, content, is_published, created_at, updated_at) VALUES ('2fcceb18-57cf-48cb-89ec-a603a49affd0', 'Designing for Yourself First', 'designing-for-yourself-first', 'The best creative work I have done started with a simple question: what would I actually want to use? A case against audience-first thinking in personal projects.', 'Design', '[{"type":"h1","text":"Designing for Yourself First"},{"type":"paragraph","text":"The best creative work I have done started with a simple question: what would I actually want to use? A case against audience-first thinking in personal projects."},{"type":"h2","text":"The Trap of Imagined Users"},{"type":"paragraph","text":"Most design advice focuses on the user. Understand their needs, build empathy, remove friction. This is correct in a professional context — you are solving someone else''s problem. But personal projects are different. When you are the primary user, second-guessing your own taste is a form of self-erasure."},{"type":"h2","text":"Taste as a Tool"},{"type":"paragraph","text":"Strong personal taste is an asset, not a liability. It gives you a clear criterion for decisions: does this feel right to me? This speeds up the design process enormously. You do not need to justify every choice to a committee. You just need to be honest with yourself."},{"type":"h2","text":"The Feedback Loop"},{"type":"paragraph","text":"When you build things you actually use, you notice problems faster. This blog is a good example. I write in the editor every day, which means I find friction immediately and fix it. No user research needed — I am the research."},{"type":"h2","text":"When This Breaks Down"},{"type":"paragraph","text":"This approach has limits. If your taste is unusual, your work may not resonate broadly. If you are not your target user, it breaks completely. The key is honesty about which situation you are in. Personal projects can afford to be personal. Products cannot."}]', true, '2026-01-08 14:00:00+05:30', '2026-01-08 14:00:00+05:30') ON CONFLICT DO NOTHING;
INSERT INTO posts (id, title, slug, excerpt, category, content, is_published, created_at, updated_at) VALUES ('14236ffb-9975-44d6-8191-c9be4bdb535c', 'The Case for Boring Technology', 'boring-technology', 'Chasing new frameworks and shiny tools is easy. Shipping reliable, maintainable software is hard. A reflection on why the most experienced engineers I know reach for the dullest solutions.', 'Engineering', '[ {"type":"h1","text":"The Case for Boring Technology"}, {"type":"paragraph","text":"At IIT Guwahati''s OSINT Lab, I spent the first three weeks of a new project evaluating stream-processing frameworks. Kafka, Flink, Pulsar, Redpanda — I read docs, ran benchmarks, wrote comparison notes. We picked Kafka because it was new to the team and felt serious. Six months later, the most painful part of running that system wasn''t the data pipeline. It was that nobody else on the team could debug it when I wasn''t around."}, {"type":"paragraph","text":"That''s the actual cost of novel technology. Not the learning curve. The dependency it creates — on the one person who climbed it."}, {"type":"h2","text":"The Novelty Tax Is Paid in Production"}, {"type":"paragraph","text":"New tools are expensive in ways that don''t show up in demos. The documentation covers the happy path. The failure modes are forum posts from 2022 with three upvotes. The error messages assume you already understand the internals. And when something breaks at 2am, your debugging strategy is basically reading source code and hoping."}, {"type":"paragraph","text":"Boring technology has already paid this tax. PostgreSQL''s error messages are comprehensible. The query planner''s behavior is documented in exhaustive detail. When you Google a Postgres problem, you get a decade of answered StackOverflow questions, not a GitHub issue labeled ''wontfix — use v2''. The senior engineer you just hired already knows it. The junior engineer can look it up. That institutional knowledge compounds over time in a way that novel tech never can early on."}, {"type":"h2","text":"Boring Is Not the Same as Weak"}, {"type":"paragraph","text":"The assumption underneath most framework-chasing is that the boring option can''t handle what you need. This is almost never true. PostgreSQL runs at Notion, Figma, and Shopify scales. Redis handles millions of operations per second. Nginx serves most of the internet. These aren''t tools you ''graduate away from'' — they''re tools that quietly scale past the point where most teams ever need to worry about them."}, {"type":"paragraph","text":"When the CLST legal translation project needed a fast lookup store for terminology, the instinct was to evaluate vector databases — it was the hot thing in NLP infrastructure. We used Redis with a sorted set. It was faster to implement, simpler to operate, and handled the load without issue. The vector DB would have been more interesting to build. Redis was correct."}, {"type":"blockquote","text":"Boring technology is usually boring because it has been refined for a long time by people who found its rough edges in production. That refinement is the whole point."}, {"type":"h2","text":"The Real Reason You Reach for Something New"}, {"type":"paragraph","text":"Be honest about motivation. Most decisions to adopt new technology are made because the new thing is interesting, not because it''s necessary. This isn''t entirely bad — engineers need to learn, and learning requires building. But those are different goals. Learning projects and production systems have different constraints, and conflating them is how you end up with a microservices architecture for a CRUD app with 200 users."}, {"type":"paragraph","text":"The test I try to run: can I write one sentence explaining what problem this technology solves that the boring alternative cannot? Not ''it''s faster'' (prove it, in your load profile, with your data). Not ''it''s more scalable'' (you have 400 users). A specific, real problem that exists today. If I can''t write that sentence, I don''t have a justification — I have enthusiasm."}, {"type":"h2","text":"When New Technology Is Actually Right"}, {"type":"paragraph","text":"There are real cases. NLLB for machine translation — there was no boring alternative that could translate court judgments into Manipuri at acceptable quality. Kafka when you genuinely need guaranteed delivery with replay semantics and your message volume is high enough to justify the operational overhead. A new framework when your existing stack has a fundamental architectural mismatch with the problem, not just a feature gap."}, {"type":"paragraph","text":"The condition isn''t ''this technology is better in the abstract.'' It''s ''this specific capability is required and the boring alternative demonstrably cannot provide it.'' That bar is higher than most teams apply it."}, {"type":"h2","text":"The Maintenance Math"}, {"type":"paragraph","text":"Here is a calculation worth running: how many hours per month will this system require to keep running, and who can do that work? Novel technology concentrates that cost on the people who understand it. When those people leave, you''re left with a system that the remaining team is afraid to touch. I''ve seen this at every place I''ve worked — a service running some less-common framework that everyone works around rather than in because the person who built it is gone."}, {"type":"paragraph","text":"Boring technology distributes maintenance cost across the whole team. Anyone can read a Postgres query. Anyone can understand an Express route. The system stays legible as people come and go. That legibility is worth paying for, even if the boring option is technically inferior in some benchmark you ran once."}, {"type":"blockquote","text":"The best technology choice isn''t the one that impresses in the architecture review. It''s the one that''s still working correctly two years later when the person who built it has moved on."}, {"type":"h2","text":"What I Actually Run"}, {"type":"paragraph","text":"This blog: Express, PostgreSQL, React, Tailwind. The ERP system at IIT Guwahati: Frappe (which is itself built on MariaDB and Python). The translation pipeline: FastAPI, PostgreSQL, Redis, Docker. Nothing in that list would get a conference talk. All of it is in production and working without incident."}, {"type":"paragraph","text":"I''m not arguing against learning new tools. I''m arguing for separating where you learn from where you ship. Experiment in side projects. Be conservative in production. The gap between what''s interesting and what''s appropriate for a system other people depend on is where most tech debt lives — and most of it was written by someone who was excited about a tool, not someone who needed it."} ]', true, '2026-02-14 16:30:00+05:30', '2026-03-20 01:09:09.660731+05:30') ON CONFLICT DO NOTHING;
INSERT INTO posts (id, title, slug, excerpt, category, content, is_published, created_at, updated_at) VALUES ('1ab8fdaf-d51c-442e-aa00-b4be0f6a2cd7', 'Reading Notes: January & February 2026', 'reading-notes-jan-feb-2026', 'A handful of books that shaped my thinking this winter — on work, attention, and the structure of the physical world.', 'Journal', '[{"type":"h1","text":"Reading Notes: January & February 2026"},{"type":"paragraph","text":"A handful of books that shaped my thinking this winter — on work, attention, and the structure of the physical world."},{"type":"h2","text":"A World Without Email — Cal Newport"},{"type":"paragraph","text":"Newport''s argument is structural: the problem with email and chat tools is not the volume of messages but the workflow model they impose. Constant, unscheduled communication fragments attention into unusable slivers. His alternative is to move toward role-based, asynchronous workflows. Practical and well-evidenced, though the prescriptions require organizational buy-in that individuals rarely have."},{"type":"h2","text":"The Timeless Way of Building — Christopher Alexander"},{"type":"paragraph","text":"A strange and beautiful book about how living structures — buildings, towns, rooms — acquire a quality that has no name except that you recognize it immediately. Alexander''s central claim is that this quality cannot be produced by following rules; it emerges from a process of careful, iterative repair. The architectural thinking maps surprisingly well onto software design."},{"type":"h2","text":"The Road to Wigan Pier — George Orwell"},{"type":"paragraph","text":"Re-reading Orwell is always instructive. His prose is a masterclass in clarity: short sentences, concrete nouns, zero abstraction when description will do. The first half, which documents working-class life in the industrial north of England, is reportage of the highest order. The second half is Orwell arguing with himself about socialism, which is less successful but more interesting."},{"type":"paragraph","text":"Currently working through Anna Karenina, slowly. It demands the kind of sustained attention I am trying to rebuild."}]', true, '2026-03-01 14:30:00+05:30', '2026-03-01 14:30:00+05:30') ON CONFLICT DO NOTHING;
INSERT INTO posts (id, title, slug, excerpt, category, content, is_published, created_at, updated_at) VALUES ('6320dbe6-7bda-4c68-99e4-564daf1f21dc', 'What I Built vs What Actually Worked', 'what-i-built-vs-what-actually-worked', 'Three years across three labs at IIT Guwahati. I shipped ML pipelines, NLP translation systems, social media analytics platforms, and an ERP. Looking back honestly, the gap between what I was confident about and what actually delivered is clarifying in places and embarrassing in others.', 'Engineering', '[ {"type":"h1","text":"What I Built vs What Actually Worked"}, {"type":"paragraph","text":"Three years across three different labs at IIT Guwahati. I shipped ML pipelines, NLP translation systems, social media analytics platforms, an ERP, and more lines of code than I can count. Looking back honestly — without the retrospective glow that usually coats these posts — the gap between what I was confident about and what actually delivered is significant. This is that accounting."}, {"type":"paragraph","text":"I am writing this not to sound humble or self-deprecating. I am writing it because I spent real time on things that didn''t matter, held wrong assumptions for months, and built features that nobody used. If I can name those clearly, maybe the next project goes better."}, {"type":"h2","text":"Project 1: The Legal Translation System — I Was Wrong About the Model"}, {"type":"paragraph","text":"At the Centre for Linguistic Science and Technology, I led development of an AI-assisted legal translation system. The task was machine translation of court judgments from English to Manipuri and other Northeast Indian languages using Meta''s NLLB model, fine-tuned on legal corpora."}, {"type":"paragraph","text":"What I thought would matter: model quality. Obsessively. The first month was almost entirely BLEU scores, model architecture comparisons, hyperparameter tuning, training run analysis. I genuinely believed that if the translation quality was high enough, everything else would follow. I was wrong."}, {"type":"paragraph","text":"What actually worked: the document editor. The plain, Word-compatible rich text editor I had deprioritized, nearly skipped, and eventually built in three days because the lawyers absolutely refused to use the interface we had. They needed something that looked and behaved like the tool they already knew. Once we had that, adoption happened. Before it, the system sat unused regardless of translation quality."}, {"type":"blockquote","text":"Lawyers do not read BLEU scores. They open documents. The interface is the product, not the model."}, {"type":"paragraph","text":"The translation accuracy mattered — up to a point. Below a certain threshold it was unusable; above it, the marginal improvements I was chasing were invisible to users. The wasted time was every training run beyond that threshold when I should have been talking to the people who would actually use the system."}, {"type":"paragraph","text":"The other wrong assumption: I thought the NLP complexity was the hard part. The genuinely hard part was structured data — entity names, case numbers, specific legal terminology that needed to stay untranslated. I hadn''t modeled that as a first-class problem, so it broke in production constantly."}, {"type":"h2","text":"Project 2: Vishleshakee 2 — When Infrastructure Becomes the Product"}, {"type":"paragraph","text":"At the OSINT Lab, I worked on Vishleshakee 2, a social media analytics platform. The stack was PySpark, Apache Kafka, Hadoop, Spark Streaming, Cassandra, and Elasticsearch. We built the full distributed pipeline."}, {"type":"paragraph","text":"I was proud of this architecture. It was genuinely sophisticated. We could ingest and process millions of events. The pipeline design was clean. I spent real effort on it and it worked."}, {"type":"paragraph","text":"Here is what I got wrong: the infrastructure complexity was solving a scale problem we mostly didn''t have yet, and building it consumed time that should have gone toward the actual research output — the sentiment analysis accuracy on specific entity types, which was what the government project was actually measuring."}, {"type":"blockquote","text":"I added complexity to solve scale problems we never actually hit, then spent the last month scrambling on the accuracy numbers that actually mattered."}, {"type":"paragraph","text":"The Kafka pipeline was elegant. The Spark Streaming integration was correct. Neither of those things were in the evaluation criteria. The named entity recognition accuracy on regional political figures was. I had it backwards."}, {"type":"paragraph","text":"What actually worked: the Elasticsearch integration for querying. Everything people used was the search and filtering interface. The streaming ingestion was mostly academic from the user''s perspective — the analysts just wanted to find things. I built a river when they needed a well."}, {"type":"paragraph","text":"The lesson I keep coming back to: I should have asked what success looks like before writing a single line of infrastructure code. I assumed scale was the problem because scale is the interesting problem. It wasn''t the actual problem."}, {"type":"h2","text":"Project 3: The ERP at the R&D Section — Customization Is a Tar Pit"}, {"type":"paragraph","text":"My current work involves building an internal ERP for IIT Guwahati''s R&D section using the Frappe Framework. Frappe is powerful, open-source, and genuinely good at a lot of things. It is also extremely easy to customize yourself into a situation you cannot maintain."}, {"type":"paragraph","text":"The wrong assumption here was about features. More modules, more complete the system, faster adoption. Logical on the surface. What actually happened: we deployed six modules in the first phase. People used two of them. One of them was just leave management, which they had been doing manually and immediately understood. The other was project budget tracking, because money is universally motivating."}, {"type":"paragraph","text":"The four modules nobody used: asset tracking, HR workflows, procurement approvals, and a reporting dashboard I built over two weeks that generated exactly zero reports in its first month of existence."}, {"type":"blockquote","text":"An ERP nobody uses is worse than a spreadsheet. A spreadsheet at least has no maintenance cost."}, {"type":"paragraph","text":"The wasted time wasn''t just building those modules — it was the customizations I kept adding trying to make them match existing paper-based processes exactly. That was the mistake. When you digitize a broken process precisely, you get a digital broken process. The org needed workflow simplification, not workflow replication."}, {"type":"paragraph","text":"What actually worked: getting two people in the R&D section to be the system''s champions before launch. Not training sessions, not documentation — two specific people who wanted the thing to work and would help their colleagues. Once I identified them and built around their feedback, adoption in their teams was fast. Everywhere else it stalled."}, {"type":"h2","text":"Project 4: This Blog — I Shipped the Container Before the Content"}, {"type":"paragraph","text":"I built this blog. Full-stack React, custom CMS, block-based editor, JWT auth, GitHub integration, newsletter subscriptions, contact management, project showcases. It took months."}, {"type":"paragraph","text":"What I thought would matter: the feature completeness. Get the platform right and the writing will follow. This is a very comfortable lie for engineers. Build the infrastructure, then fill it."}, {"type":"paragraph","text":"The honest version: I spent more time building the admin dashboard than I spent writing. I have a GitHub heatmap on the public site. I have server-side pagination on the contacts table. I have a contribution activity feed with emoji icons. I do not have a consistent writing habit."}, {"type":"blockquote","text":"I optimized the publishing infrastructure before I had anything worth publishing regularly. That is backwards."}, {"type":"paragraph","text":"What actually worked: writing the seed posts. Not the features, not the CMS — just putting actual words in. The posts that exist are more useful to me than the newsletter system I spent a week on."}, {"type":"paragraph","text":"The lesson isn''t that the infrastructure was wrong to build. It''s that I used building it as a substitute for the harder, less tangible work of actually writing. Feature development is measurable and satisfying in a way that writing is not. I used that to avoid the thing I was ostensibly building the platform for."}, {"type":"h2","text":"The Pattern I Keep Finding"}, {"type":"paragraph","text":"Looking across these four projects, the wrong assumptions cluster around the same mistake: I was optimizing for what I found technically interesting rather than what the person using the system actually needed from it."}, {"type":"paragraph","text":"The NLLB model was interesting. The Kafka pipeline was interesting. The ERP module coverage was interesting. The blog infrastructure was interesting. The lawyers needed a document editor. The analysts needed search. The R&D section needed two things to work reliably. I needed to write."}, {"type":"paragraph","text":"None of this is a novel observation. Every engineering retrospective eventually lands here. What''s harder is that knowing it doesn''t protect you from doing it again. The technically interesting thing is always right in front of you, and the thing that actually matters requires talking to people or sitting with discomfort."}, {"type":"blockquote","text":"The technically hard problem is rarely the actual problem. The actual problem is usually boring and requires talking to people."}, {"type":"paragraph","text":"What I''m trying to do differently: before any significant technical decision, write one sentence about what success looks like for the person who isn''t me. Not for the architecture, not for the benchmark, not for the codebase — for the person who has to use it. If I can''t write that sentence clearly, I don''t know enough to build yet."}, {"type":"paragraph","text":"That''s it. No framework, no five-step process. Just that one check, done honestly, before the interesting work starts."} ]', true, '2026-03-20 13:30:00+05:30', '2026-03-20 13:30:00+05:30') ON CONFLICT DO NOTHING;
INSERT INTO posts (id, title, slug, excerpt, category, content, is_published, created_at, updated_at) VALUES ('30b4ece8-6363-4e32-8ef1-d39c27ad6ebd', 'Why Most of My Ideas Are Trash', 'why-most-of-my-ideas-are-trash', 'A cold autopsy of the ideas I was convinced would work. No motivational arc. Just the actual reasons they failed — no real users, wrong problem, overengineered, or never finished because I ran out of genuine interest.', 'Journal', E'[ {"type":"h1","text":"Why Most of My Ideas Are Trash"}, {"type":"paragraph","text":"I keep a note where I dump project ideas. It has 47 entries. Three of them became anything real. That is a six percent hit rate, and I am being generous about what counts as real."}, {"type":"paragraph","text":"This is not an essay about how failure is secretly success, or how the thirty-second iteration teaches you something the first one couldn''t. That framing is a cope. The honest version is: most of my ideas are bad, I have consistent blind spots that make them bad in predictable ways, and I have been slow to accept that. This is the autopsy."}, {"type":"h2","text":"The Ideas That Were Really Just Features"}, {"type":"paragraph","text":"At least a third of my idea list is not ideas — it is features that belong inside something that already exists. A script that formats Readwise highlights into a specific structure I like. A browser extension that strips UTM parameters. A CLI tool that reformats JSON the way I prefer."}, {"type":"paragraph","text":"None of these are products. None of them have users other than me, and most of the time not even me — I build the thing, use it twice, and then forget it exists. I put them on the list as if having a name and a repo makes them projects. It does not."}, {"type":"blockquote","text":"A script you wrote for yourself is not a product. It is automation. Calling it a project is a way of feeling productive without doing anything that matters."}, {"type":"paragraph","text":"The tell: if explaining the idea to someone requires more than one sentence of context-setting before you even get to what the thing does, it is a feature. Features are fine. Just do not confuse building a feature with building something."}, {"type":"h2","text":"The Scratch-Your-Own-Itch Trap"}, {"type":"paragraph","text":"There is a theory that the best products come from solving your own problems. It is true in limited cases and catastrophically misapplied in most others. The version that actually holds: if you have a problem AND can verify that other people have the exact same problem AND they currently solve it badly enough to pay or change behavior to get a better solution — then yes, scratch it."}, {"type":"paragraph","text":"What I actually do: I have a minor inconvenience. I assume everyone has it. I build something. Nobody uses it because the inconvenience was either unique to my workflow or not painful enough for anyone else to care about."}, {"type":"paragraph","text":"The Readwise formatter is a good example. I wanted highlights reformatted a specific way for a personal review system I built. Nobody else has that review system. The formatter is therefore useless to anyone except me in a configuration nobody else runs. I spent three days on it. The problem it solved had a ten-minute manual workaround that most people would just do."}, {"type":"blockquote","text":"Your inconvenience is not automatically a market. The gap between \\"I find this annoying\\" and \\"people will change their behavior to fix this\\" is where most ideas die, and it deserves more scrutiny than I have historically given it."}, {"type":"h2","text":"The Tech-First Mistake"}, {"type":"paragraph","text":"Some of my worst ideas started with a technology I wanted to use rather than a problem I wanted to solve. I learned Kafka and Spark Streaming properly while building the social media analytics pipeline at IIT Guwahati. Coming out of that, I had three or four ideas for things to build with those tools. All of them were bad."}, {"type":"paragraph","text":"The structure of these ideas is recognizable in retrospect: I know tool X. Tool X is powerful for use case Y. I do not have use case Y, but I will find a problem that sounds like Y and work backwards from there. The result is always an over-engineered solution to a problem that did not actually require that solution — or was not really a problem at all."}, {"type":"paragraph","text":"I designed a real-time event ingestion system for a personal finance tracker I had in mind. Real-time ingestion for personal finance. My own spending data. Coming in at what — maybe forty transactions a month? I was going to build a Kafka pipeline for forty events a month because I had just learned Kafka and wanted to use it for something."}, {"type":"blockquote","text":"When the technology is the interesting part and the problem is something you invented to justify using it, you are not solving anything. You are practicing, and you should call it that."}, {"type":"paragraph","text":"The practice itself is fine. Building something with a new tool to learn it is legitimate. The mistake is pretending it is a product."}, {"type":"h2","text":"The Fake Validation"}, {"type":"paragraph","text":"I have shown ideas to people and interpreted politeness as validation. This is probably the most consistently costly mistake on the list."}, {"type":"paragraph","text":"When you describe an idea enthusiastically, most people will not tell you it is bad. They will say it sounds interesting, or ask a clarifying question, or say they could see that being useful. None of that is validation. That is someone being socially functional."}, {"type":"paragraph","text":"Real validation is behavior change. Someone adjusting what they are currently doing because your thing is better. Someone coming back after the first use. Someone describing the problem to you without prompting in a way that matches what you thought the problem was. I have almost never had this before starting to build. I have frequently had encouraging conversations and treated that as equivalent."}, {"type":"paragraph","text":"The ERP module I spent two weeks building — the reporting dashboard that generated zero reports in its first month — I had talked to three people about it beforehand. They all said it would be useful. What I did not ask: do you currently need to report on this, how often, and what would you stop doing to use a new system for it? The answer to all three was effectively no, rarely, and nothing."}, {"type":"blockquote","text":"Asking someone if they would use something is nearly worthless. Watching whether they use it is the only data that counts."}, {"type":"h2","text":"The Project I Loved More Than the Problem"}, {"type":"paragraph","text":"This blog is the clearest example of this failure mode I have, and I am still in it."}, {"type":"paragraph","text":"I built a custom CMS with a block editor, JWT auth, admin dashboard, GitHub integration that shows my contribution heatmap, server-side paginated contact management, newsletter subscriptions — the infrastructure is real and it works. I spent more time building the publishing platform than I have spent publishing."}, {"type":"paragraph","text":"The idea was: have a place to write and share what I am thinking. The execution was: build an increasingly elaborate system that makes writing feel like a reward for finishing the infrastructure, which is never actually finished."}, {"type":"paragraph","text":"I know this pattern. I have done it before. I wrote a task management system instead of managing my tasks. I built a note-taking tool instead of taking notes. The building is more comfortable than the use because building has clear completion states and the actual use — writing, thinking, producing something — does not."}, {"type":"blockquote","text":"Building the tool is not the same as doing the work. The tool is an obstacle with good UI."}, {"type":"paragraph","text":"The difference between this and the tech-first mistake is motivation. The tech-first mistake is intellectual curiosity misdirected. This one is avoidance. I do not love writing enough to do it uncomfortably, so I build infrastructure that makes it more comfortable, which mostly means I do not have to write at all."}, {"type":"h2","text":"The Ideas That Were Genuinely Good and Still Failed"}, {"type":"paragraph","text":"The hardest category to be honest about: ideas with real users, a real problem, and real demand — that I did not execute well enough or long enough to make work."}, {"type":"paragraph","text":"The legal translation system at CLST is in this category. The lawyers had a real problem. The system worked. I built the wrong interface for the first six months because I assumed they would adapt to what I built rather than asking what they needed. By the time we had the right interface, the project funding cycle was ending."}, {"type":"paragraph","text":"Good idea, wrong assumption about users, slow to correct. That is a different failure than having a bad idea, but it is still a failure of execution. I held a wrong belief — that the translation quality was the primary driver of adoption — for longer than the evidence warranted, because it was the technically interesting belief to hold."}, {"type":"paragraph","text":"There is no clean lesson here. The same impulse that makes you good at the technical problem makes you slow to see that the technical problem is not the actual problem. I do not know how to remove that bias. I just know it is there."}, {"type":"h2","text":"What the Pattern Is"}, {"type":"paragraph","text":"Across all of these, the common thread is a willingness to substitute something measurable for something harder. Building for a technology instead of a problem. Building the tool instead of doing the work. Getting encouraging words instead of watching actual behavior. Optimizing the model instead of talking to users."}, {"type":"paragraph","text":"The measurable thing is always available. Lines of code, benchmark numbers, feature count, conversation count — these exist and can be tracked. The hard thing — whether anyone actually needs this, whether I am the right person to build it, whether I am building it because it matters or because it is interesting — requires sitting with uncertainty and often produces no clear answer."}, {"type":"paragraph","text":"I am faster at the measurable thing than most people I know. I am slower than I should be at the hard thing. That ratio explains most of the entries in the note with 47 ideas."}, {"type":"blockquote","text":"The ideas are not trash because I am bad at ideas. They are trash because I am better at building than questioning, and I use that asymmetry to avoid the questioning."}, {"type":"paragraph","text":"I do not have a solution to this. The awareness does not fully correct for it — I have known about this pattern for at least two years and still fall into it. What I do now is at least wait longer before starting to build, try to identify which category the idea is in, and stay suspicious of enthusiasm. Enthusiasm, in my experience, is most intense precisely when I have thought about the idea the least."} ]', true, '2026-03-20 15:00:00+05:30', '2026-03-20 00:38:46.96206+05:30') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, title, category, description, tags, status, image_seed, sort_order, created_at) VALUES ('3aceb821-f00e-43f3-8208-0ce4ddd22b7d', 'Organic Minimalism Blog', 'Engineering', 'This site. A custom CMS and blog built with React, Express, and PostgreSQL. Features a block-based editor, JWT-authenticated admin panel, and a clean reading experience designed from scratch.', '["React","TypeScript","PostgreSQL","Express"]', 'Live', 'blog-cms', 1, '2026-03-19 23:31:36.658981+05:30') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, title, category, description, tags, status, image_seed, sort_order, created_at) VALUES ('74a3fc7b-f9a0-4ddb-8cf8-0b1611ac3da4', 'Readwise CLI Companion', 'Engineering', 'A command-line tool that pulls highlights from Readwise and formats them into a daily review digest. Supports Markdown export, filtered queries by tag and date, and a plain-text output mode for terminal readers.', '["Node.js","TypeScript","REST API","CLI"]', 'Open Source', 'terminal-tool', 2, '2026-03-19 23:31:36.664686+05:30') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, title, category, description, tags, status, image_seed, sort_order, created_at) VALUES ('e70239de-a6bd-4f25-a799-2ec9e7031190', 'Personal Type System', 'Design', 'A personal typographic system exploring the pairing of Cormorant Garamond with Inter across editorial contexts. Includes scale specimens, line-length studies, and a contrast grid for light and dark surfaces.', '["Typography","Figma","CSS"]', 'Ongoing', 'typography-specimen', 3, '2026-03-19 23:31:36.665382+05:30') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, title, category, description, tags, status, image_seed, sort_order, created_at) VALUES ('998f0656-16ae-4d3f-9ab1-c7ceabf5363b', 'PostgreSQL Backup Monitor', 'Engineering', 'A self-hosted service that verifies nightly PostgreSQL backups are completing successfully and sends a daily digest. Built after a silent backup failure left a production database unprotected for two weeks.', '["Node.js","PostgreSQL","Cron","SMTP"]', 'Open Source', 'server-infra', 4, '2026-03-19 23:31:36.666874+05:30') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, title, category, description, tags, status, image_seed, sort_order, created_at) VALUES ('e2d3dd4e-82ee-4931-b2e5-47353f02c03f', 'Focus Mode — Browser Extension', 'UX/UI', 'A minimal browser extension that dims non-essential page elements and strips tracking parameters from URLs. Designed around a single principle: the web should serve the reader, not the other way around.', '["JavaScript","Browser Extension","CSS"]', 'Live', 'browser-ext', 5, '2026-03-19 23:31:36.667416+05:30') ON CONFLICT DO NOTHING;
INSERT INTO projects (id, title, category, description, tags, status, image_seed, sort_order, created_at) VALUES ('7d8041ee-d22b-4b0a-9f16-f84a63f8febd', 'Color in Interface Design', 'Design', 'A research project studying how restrained color palettes affect user attention and perceived quality in web interfaces. Includes annotated case studies of six published products and a set of decision heuristics.', '["UX Research","Color Theory","Figma"]', 'Complete', 'color-study', 6, '2026-03-19 23:31:36.668219+05:30') ON CONFLICT DO NOTHING;
